/* =============================================
   ERGuide Globe — exact replication of
   erguide.co.za hologram globe logic.
   Source: _nuxt/c548523.js (decompiled)
   ============================================= */

(function () {
  'use strict';

  /* --- Country data (exact from ERGuide source) --- */
  var photos = [
    { location: { lat: -29.347968, lng: 24.835125 }, image: 'data:image/svg+xml;base64,',   name: 'South Africa',                    scale: 1.6 },
    { location: { lat: -13.888319, lng: 28.471788 }, image: 'data:image/svg+xml;base64,',          name: 'Zambia',                          scale: 1.3 },
    { location: { lat:   1.23389,  lng: 30.49063  }, image: 'data:image/svg+xml;base64,',          name: 'Uganda',                          scale: 1.2 },
    { location: { lat:  -6.540242, lng: 36.399742 }, image: 'data:image/svg+xml;base64,',        name: 'Tanzania',                        scale: 1.2 },
    { location: { lat: -20.288987, lng: 57.604131 }, image: 'data:image/svg+xml;base64,',       name: 'Mauritius',                       scale: 0.5 },
    { location: { lat: -11.579902, lng: 35.255198 }, image: 'data:image/svg+xml;base64,',          name: 'Malawi',                          scale: 1.2 },
    { location: { lat:   0.205868, lng: 38.298401 }, image: 'data:image/svg+xml;base64,',           name: 'Kenya',                           scale: 1.2 },
    { location: { lat:   8.14274,  lng: -0.962885 }, image: 'data:image/svg+xml;base64,',           name: 'Ghana',                           scale: 0.95},
    { location: { lat:   9.720113, lng: 41.56498  }, image: 'data:image/svg+xml;base64,',        name: 'Ethiopia',                        scale: 1.2 },
    { location: { lat:  -3.2182928,lng: 18.1973187}, image: 'data:image/svg+xml;base64,',           name: 'Democratic Republic of the Congo',scale: 1.5 },
    { location: { lat: -22.765682, lng: 18.13689  }, image: 'data:image/svg+xml;base64,',         name: 'Namibia',                         scale: 1.2 },
    { location: { lat: -10.638468, lng: 17.737262 }, image: 'data:image/svg+xml;base64,',          name: 'Angola',                          scale: 1.5 },
    { location: { lat: -26.60879,  lng: 31.487988 }, image: 'data:image/svg+xml;base64,',        name: 'Eswatini',                        scale: 0.7 },
    { location: { lat: -29.64702,  lng: 28.255827 }, image: 'data:image/svg+xml;base64,',         name: 'Lesotho',                         scale: 0.7 },
    { location: { lat: -21.653204, lng: 23.936888 }, image: 'data:image/svg+xml;base64,',        name: 'Botswana',                        scale: 1.4 },
    { location: { lat:   8.9999,   lng:  9.336075 }, image: 'data:image/svg+xml;base64,',         name: 'Nigeria',                         scale: 1.5 },
    { location: { lat: -17.735608, lng: 37.212983 }, image: 'data:image/svg+xml;base64,',      name: 'Mozambique',                      scale: 1.4 },
  ];

  var myearth      = null;
  var sprites      = [];
  var photoOverlay = null;
  var clippedLine  = null;
  var source       = 0;
  var destination  = 1;
  var currentMarker= null;
  var globeLive    = true;

  /* --- Boot: load miniature.earth.js dynamically then init --- */
  function attachEarth() {
    if (window.Earth) {
      createGlobe();
    } else {
      window.addEventListener('earthjsload', createGlobe, { once: true });
    }
  }

  function createGlobe() {
    if (!globeLive) return;

    myearth = new window.Earth('myearth', {
      location:        { lat: 6.6112329, lng: 16.4384161 }, // centred on Africa
      light:           'simple',
      lightColor:      '#000000',
      lightIntensity:  5,
      mapImage: 'data:image/svg+xml;base64,',
      transparent:     true,
      autoRotate:      true,
      autoRotateSpeed: 0.2,
      autoRotateDelay: 300,
      autoRotateStart: 3000,
      draggable:       true,
    });

    myearth.addEventListener('ready', function () {
      if (!globeLive) { myearth.destroy(); myearth = null; return; }

      /* Country name overlay (exact ERGuide HTML) */
      photoOverlay = myearth.addOverlay({
        content:        '<div class="card"><p id="country-name"></p></div>',
        visible:        true,
        containerScale: 1,
        depthScale:     0,
      });

      /* Add sprite image at each country location */
      for (var i = 0; i < photos.length; i++) {
        sprites[i] = myearth.addImage({
          location: photos[i].location,
          image:    photos[i].image,
          scale:    photos[i].scale,
          opacity:  0,
          hotspot:  true,
        });
      }

      /* Start the animated line sequence */
      if (globeLive) shootLine();
    });

    /* Close photo if globe rotates too far from current marker */
    myearth.addEventListener('dragstart', function () {
      myearth.stopAutoRotate();
    });
    myearth.addEventListener('dragend', function () {
      setTimeout(function () {
        if (myearth) myearth.startAutoRotate();
      }, 2500);
    });

    myearth.addEventListener('change', function () {
      if (currentMarker && !myearth.autoRotate) {
        if (window.Earth.getAngle(myearth.location, currentMarker.location) > 45) {
          closePhoto();
        }
      }
    });
  }

  /* --- Shoot animated connection line between source → destination --- */
  function shootLine() {
    if (!myearth || !globeLive) return;

    var lineConfig = {
      locations:  [ photos[source].location, photos[destination].location ],
      clip:       0,
      offset:     -0.3,
      offsetFlow: 2,
      color:      '#02e67f',
      width:      0.3,
    };

    if (clippedLine) {
      clippedLine.animate('opacity', 0, {
        loop:       false,
        oscillate:  false,
        duration:   500,
        complete: function () {
          clippedLine.remove();
          clippedLine = myearth.addLine(lineConfig);
          clippedLine.animate('clip', 1, {
            loop:      false,
            oscillate: false,
            duration:  2000,
            complete: function () { pulse(destination); },
          });
        },
      });
    } else {
      clippedLine = myearth.addLine(lineConfig);
      clippedLine.animate('clip', 1, {
        loop:      false,
        oscillate: false,
        duration:  2000,
        complete: function () { pulse(destination); },
      });
    }
  }

  /* --- Pulse a sprite and open country photo overlay --- */
  function pulse(idx) {
    if (!sprites[idx]) return;
    closePhoto();

    sprites[idx].animate('opacity', 1, {
      duration: 1000,
      complete: function () {
        openPhoto(photos[idx]);

        source++;
        destination = source + 1;
        if (destination >= sprites.length) destination = 0;
        if (source >= sprites.length)      { source = 0; destination = source + 1; }

        if (globeLive) shootLine();

        sprites[idx].animate('opacity', 0, { duration: 5000, complete: function () {} });
      },
    });
  }

  /* --- Show country overlay card --- */
  function openPhoto(photo) {
    var el = document.getElementById('country-name');
    if (el) el.innerHTML = photo.name;
    if (photoOverlay) {
      photoOverlay.location = photo.location;
      photoOverlay.visible  = true;
    }
    currentMarker = photo;
  }

  /* --- Hide overlay --- */
  function closePhoto() {
    if (photoOverlay) photoOverlay.visible = false;
    currentMarker = null;
  }

  /* --- Init on DOM ready --- */
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', attachEarth);
  } else {
    attachEarth();
  }

  /* --- Cleanup on page hide (memory) --- */
  document.addEventListener('visibilitychange', function () {
    if (document.hidden) {
      globeLive = false;
      if (myearth) { myearth.destroy(); myearth = null; }
    }
  });

})();
